import {
  BotonTema,
  Footer,
  Header2,
  Github,
} from "../reutilizables/componentes";

import { useState } from "react";

function UsuarioContraseña() {
  const [idUsuarios, setidUsuarios] = useState("");
  const [contraseña, setContraseña] = useState("");
  const handleLogin = async () => {
    console.log("Intentando iniciar sesión con:", idUsuarios, contraseña);
  };

  return (
    <div>
      <BotonTema />
      <div id="container">
        <header id="header1">
          <button id="volver" onClick={() => window.history.back()}>
            volver
          </button>
        </header>
        <Header2 />

        <section id="content">
          <input
            type="text"
            id="usuario"
            placeholder="usuario"
            className="userInput"
            value={idUsuarios}
            onChange={(e) => setidUsuarios(e.target.value)}
          ></input>
          <input
            type="password"
            id="contraseña"
            placeholder="contraseña"
            className="userInput"
            value={contraseña}
            onChange={(e) => setContraseña(e.target.value)}
          ></input>
          <button
            id="iniciarSesion"
            className="principales"
            onClick={handleLogin}
          >
            iniciar sesion
          </button>
          <a id="recuperacion" href="/cambiarContraseña">
            ¿olvidaste tu contraseña?
          </a>
          <p></p>
        </section>
        <Footer />
      </div>
      <Github />
    </div>
  );
}
export default UsuarioContraseña;
